#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BS 16

__kernel void lud_diagonal(__global float* a, __local float* shared_mem, int size, int offset) {
    int i = get_global_id(0);
    if (i >= BS) return;

    // Macro replacements for AA(i,j) = a[offset*size + i*size + j + offset]
    #define AA(_i,_j) a[(offset)*size + (_i)*size + (_j) + (offset)]

    for (int j = i; j < BS; j++) {
        for (int k = 0; k < i; k++) {
            AA(i,j) = AA(i,j) - AA(i,k) * AA(k,j);
        }
    }

    float temp = 1.f / AA(i,i);
    for (int j = i + 1; j < BS; j++) {
        for (int k = 0; k < i; k++) {
            AA(j,i) = AA(j,i) - AA(j,k) * AA(k,i);
        }
        AA(j,i) = AA(j,i) * temp;
    }
    #undef AA
}

__kernel void lud_perimeter(__global float* a, __local float* temp_diag, __local float* temp_shared, __local float* temp_shared2, int size, int offset) {
    int gid = get_global_id(0);
    int lid = get_local_id(0);
    int group_size = get_local_size(0);

    int chunk_idx = gid / BS;
    int i, j, k;
    int i_global = offset;
    int j_global = offset;

    // Macro for BB(i,j) = a[i*size + j]
    #define BB(_i,_j) a[(_i)*size + (_j)]

    // Load temp from diagonal block
    for (i = lid; i < BS; i += group_size) {
        for (j = 0; j < BS; j++) {
            temp_diag[i*BS + j] = a[size*(i + offset) + offset + j];
        }
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    j_global += BS * (chunk_idx + 1);

    for (j = 0; j < BS; j++) {
        for (i = 0; i < BS; i++) {
            float sum = 0.f;
            for (k = 0; k < i; k++) {
                sum += temp_diag[BS*i + k] * BB((i_global + k), (j_global + j));
            }
            int i_here = i_global + i;
            int j_here = j_global + j;
            BB(i_here, j_here) = BB(i_here, j_here) - sum;
        }
    }

    j_global = offset;
    i_global += BS * (chunk_idx + 1);

    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            float sum = 0.f;
            for (k = 0; k < j; k++) {
                sum += BB((i_global + i), (j_global + k)) * temp_diag[BS*k + j];
            }
            int i_here = i_global + i;
            int j_here = j_global + j;
            a[size*i_here + j_here] = (a[size*i_here + j_here] - sum) / a[size*(offset + j) + offset + j];
        }
    }
    #undef BB
}

__kernel void lud_internal(__global float* a, __local float* temp_top, __local float* temp_left, int size, int offset) {
    int gid_x = get_global_id(0);
    int gid_y = get_global_id(1);
    int lid_x = get_local_id(0);
    int lid_y = get_local_id(1);
    int group_size_x = get_local_size(0);
    int group_size_y = get_local_size(1);

    int chunks_in_inter_row = (size - offset - BS) / BS;
    int chunk_idx = gid_y * chunks_in_inter_row + gid_x;

    int i_global = offset + BS * (1 + (chunk_idx / chunks_in_inter_row));
    int j_global = offset + BS * (1 + (chunk_idx % chunks_in_inter_row));

    // Load temp_top and temp_left from global memory to local memory
    for (int i = lid_y; i < BS; i += group_size_y) {
        for (int j = lid_x; j < BS; j += group_size_x) {
            temp_top[i*BS + j] = a[size*(i + offset) + j + j_global];
            temp_left[i*BS + j] = a[size*(i + i_global) + offset + j];
        }
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    float sum[BS];
    for (int idx = 0; idx < BS; idx++) sum[idx] = 0.f;

    for (int i = lid_y; i < BS; i += group_size_y) {
        for (int k = 0; k < BS; k++) {
            for (int j = lid_x; j < BS; j += group_size_x) {
                sum[j] += temp_left[BS*i + k] * temp_top[BS*k + j];
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);
        for (int j = lid_x; j < BS; j += group_size_x) {
            a[(i + i_global)*size + (j + j_global)] -= sum[j];
            sum[j] = 0.f;
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }
}
